package main

import (
    "crypto/rand"
    "crypto/sha256"
    "encoding/binary"
    "encoding/gob"
    "encoding/json"
    "io"
    "log"
    "net"
    "net/http"
    "net/url"
    "os"
    "sort"
    "sync"
)

const (
    H       = 32
    MaxBody = 256 << 20

    OP_REGISTER byte = 1
    OP_UPLOAD   byte = 2
    OP_FILE     byte = 3
    OP_EDGE     byte = 4
    OP_CHILDREN byte = 5
    OP_VOTE     byte = 6
    OP_USET     byte = 7
    OP_UGET     byte = 8

    OK        byte = 0
    ERR_BAD   byte = 1
    ERR_DENY  byte = 2
    ERR_NF    byte = 3
    ERR_BIG   byte = 4
    ERR_INNER byte = 5
)

type Hash [H]byte
type Identity [H]byte

type UserKey struct {
    User Identity
    Key  Hash
}

type Edge struct {
    Parent Hash
    Child  Hash
}

type VoteKey struct {
    User   Identity
    Parent Hash
    Child  Hash
}

type DB struct {
    Files map[Hash][]byte
    Graph map[Hash][]Hash
    Users map[Identity]bool
    Vals  map[UserKey]Hash
    Score map[Edge]int64
    Voted map[VoteKey]bool
    Seq   map[Edge]int64
    Next  int64
}

type App struct {
    mu     sync.Mutex
    dbFile string
    secret string
    db     DB
}

func newDB() DB {
    return DB{
        Files: map[Hash][]byte{},
        Graph: map[Hash][]Hash{},
        Users: map[Identity]bool{},
        Vals:  map[UserKey]Hash{},
        Score: map[Edge]int64{},
        Voted: map[VoteKey]bool{},
        Seq:   map[Edge]int64{},
    }
}

func hashFrom(b []byte) Hash {
    var h Hash
    copy(h[:], b)
    return h
}

func idFrom(b []byte) Identity {
    var id Identity
    copy(id[:], b)
    return id
}

func hasChild(xs []Hash, h Hash) bool {
    for _, x := range xs {
        if x == h {
            return true
        }
    }
    return false
}

func (a *App) load() {
    a.db = newDB()

    f, err := os.Open(a.dbFile)
    if err != nil {
        return
    }
    defer f.Close()

    _ = gob.NewDecoder(f).Decode(&a.db)

    if a.db.Files == nil {
        a.db.Files = map[Hash][]byte{}
    }
    if a.db.Graph == nil {
        a.db.Graph = map[Hash][]Hash{}
    }
    if a.db.Users == nil {
        a.db.Users = map[Identity]bool{}
    }
    if a.db.Vals == nil {
        a.db.Vals = map[UserKey]Hash{}
    }
    if a.db.Score == nil {
        a.db.Score = map[Edge]int64{}
    }
    if a.db.Voted == nil {
        a.db.Voted = map[VoteKey]bool{}
    }
    if a.db.Seq == nil {
        a.db.Seq = map[Edge]int64{}
    }
}

func (a *App) save() {
    tmp := a.dbFile + ".tmp"

    f, err := os.Create(tmp)
    if err != nil {
        return
    }

    err = gob.NewEncoder(f).Encode(a.db)
    cerr := f.Close()

    if err == nil && cerr == nil {
        _ = os.Rename(tmp, a.dbFile)
    }
}

func (a *App) verifyTurnstile(token string) bool {
    if a.secret == "" {
        return true
    }

    form := url.Values{
        "secret":   {a.secret},
        "response": {token},
    }

    resp, err := http.PostForm(
        "https://challenges.cloudflare.com/turnstile/v0/siteverify",
        form,
    )
    if err != nil {
        return false
    }
    defer resp.Body.Close()

    var out struct {
        Success bool `json:"success"`
    }

    _ = json.NewDecoder(resp.Body).Decode(&out)
    return out.Success
}

func readFrame(c net.Conn) (byte, []byte, error) {
    var h [5]byte

    if _, err := io.ReadFull(c, h[:]); err != nil {
        return 0, nil, err
    }

    n := binary.BigEndian.Uint32(h[1:5])
    if n > MaxBody {
        return h[0], nil, io.ErrShortBuffer
    }

    b := make([]byte, n)
    if n != 0 {
        if _, err := io.ReadFull(c, b); err != nil {
            return 0, nil, err
        }
    }

    return h[0], b, nil
}

func writeFrame(c net.Conn, status byte, body []byte) error {
    var h [5]byte

    h[0] = status
    binary.BigEndian.PutUint32(h[1:5], uint32(len(body)))

    if _, err := c.Write(h[:]); err != nil {
        return err
    }

    if len(body) != 0 {
        _, err := c.Write(body)
        return err
    }

    return nil
}

func (a *App) handle(op byte, body []byte) (byte, []byte) {
    switch op {
    case OP_REGISTER:
        if !a.verifyTurnstile(string(body)) {
            return ERR_DENY, nil
        }

        var id Identity
        if _, err := rand.Read(id[:]); err != nil {
            return ERR_INNER, nil
        }

        a.mu.Lock()
        a.db.Users[id] = true
        a.save()
        a.mu.Unlock()

        return OK, id[:]

    case OP_UPLOAD:
        if len(body) == 0 {
            return ERR_BAD, nil
        }

        sum := sha256.Sum256(body)
        h := Hash(sum)

        a.mu.Lock()
        if _, exists := a.db.Files[h]; !exists {
            a.db.Files[h] = append([]byte(nil), body...)
            a.save()
        }
        a.mu.Unlock()

        return OK, h[:]

    case OP_FILE:
        if len(body) != 32 {
            return ERR_BAD, nil
        }

        h := hashFrom(body)

        a.mu.Lock()
        raw, found := a.db.Files[h]
        out := append([]byte(nil), raw...)
        a.mu.Unlock()

        if !found {
            return ERR_NF, nil
        }

        return OK, out

    case OP_EDGE:
        if len(body) != 64 {
            return ERR_BAD, nil
        }

        parent := hashFrom(body[:32])
        child := hashFrom(body[32:64])

        a.mu.Lock()
        if !hasChild(a.db.Graph[parent], child) {
            a.db.Graph[parent] = append(a.db.Graph[parent], child)
            a.save()
        }
        a.mu.Unlock()

        return OK, nil

    case OP_CHILDREN:
        if len(body) != 32 {
            return ERR_BAD, nil
        }

        parent := hashFrom(body)

        a.mu.Lock()

        list := append([]Hash(nil), a.db.Graph[parent]...)

        sort.SliceStable(list, func(i, j int) bool {
            ei := Edge{parent, list[i]}
            ej := Edge{parent, list[j]}

            if a.db.Score[ei] != a.db.Score[ej] {
                return a.db.Score[ei] > a.db.Score[ej]
            }

            return a.db.Seq[ei] > a.db.Seq[ej]
        })

        out := make([]byte, 4+len(list)*40)
        binary.BigEndian.PutUint32(out[:4], uint32(len(list)))

        off := 4
        for _, child := range list {
            copy(out[off:off+32], child[:])
            off += 32

            score := a.db.Score[Edge{parent, child}]
            binary.BigEndian.PutUint64(out[off:off+8], uint64(score))
            off += 8
        }

        a.mu.Unlock()

        return OK, out

    case OP_VOTE:
        if len(body) != 96 {
            return ERR_BAD, nil
        }

        user := idFrom(body[:32])
        parent := hashFrom(body[32:64])
        child := hashFrom(body[64:96])

        a.mu.Lock()
        defer a.mu.Unlock()

        if !a.db.Users[user] {
            return ERR_DENY, nil
        }

        if !hasChild(a.db.Graph[parent], child) {
            return ERR_BAD, nil
        }

        vk := VoteKey{user, parent, child}
        e := Edge{parent, child}

        if !a.db.Voted[vk] {
            a.db.Voted[vk] = true
            a.db.Score[e]++
        }

        a.db.Next++
        a.db.Seq[e] = a.db.Next

        a.save()

        return OK, nil

    case OP_USET:
        if len(body) != 96 {
            return ERR_BAD, nil
        }

        user := idFrom(body[:32])
        key := hashFrom(body[32:64])
        val := hashFrom(body[64:96])

        a.mu.Lock()
        defer a.mu.Unlock()

        if !a.db.Users[user] {
            return ERR_DENY, nil
        }

        a.db.Vals[UserKey{user, key}] = val
        a.save()

        return OK, nil

    case OP_UGET:
        if len(body) != 64 {
            return ERR_BAD, nil
        }

        user := idFrom(body[:32])
        key := hashFrom(body[32:64])

        a.mu.Lock()
        defer a.mu.Unlock()

        if !a.db.Users[user] {
            return ERR_DENY, nil
        }

        val, found := a.db.Vals[UserKey{user, key}]
        if !found {
            return ERR_NF, nil
        }

        return OK, val[:]
    }

    return ERR_BAD, nil
}

func (a *App) serve(c net.Conn) {
    defer c.Close()

    for {
        op, body, err := readFrame(c)
        if err != nil {
            return
        }

        status, out := a.handle(op, body)

        if writeFrame(c, status, out) != nil {
            return
        }
    }
}

func main() {
    app := &App{
        dbFile: "cvm.gob",
        secret: os.Getenv("CF_TURNSTILE_SECRET"),
    }

    app.load()

    ln, err := net.Listen("tcp", ":9000")
    if err != nil {
        panic(err)
    }

    log.Println("CVM binary TCP server listening on :9000")

    for {
        c, err := ln.Accept()
        if err == nil {
            go app.serve(c)
        }
    }
}

